import React, { useState, useRef } from 'react';
import api from '../api/api';
import { FaUpload, FaCamera, FaSpinner, FaCheckCircle, FaTimesCircle, FaChartPie, FaChartBar } from 'react-icons/fa';

const CalorieUpload = ({ profile, fetchNutrientWarnings }) => {
    
    const fileInputRef = useRef(null); 
    
    const [mealType, setMealType] = useState(''); 
    const [uploadedFile, setUploadedFile] = useState(null); 
    const [prediction, setPrediction] = useState(null);
    const [loading, setLoading] = useState(false);
    const [uploadError, setUploadError] = useState('');
    const [uploadMessage, setUploadMessage] = useState('');

    const calculateDailyTargets = (dailyCalorieTarget, goal) => {
        const target = Number(dailyCalorieTarget); 
        if (!target || target === 0) return { protein: 0, fat: 0, carbs: 0 };

        let proteinPercent, fatPercent, carbPercent;

        switch (goal) {
            case 'lose':
                proteinPercent = 0.45; 
                fatPercent = 0.30;
                carbPercent = 0.25;
                break;
            case 'gain':
                proteinPercent = 0.35;
                fatPercent = 0.30;
                carbPercent = 0.35;
                break;
            case 'maintain':
            default:
                proteinPercent = 0.40;
                fatPercent = 0.30;
                carbPercent = 0.30;
                break;
        }

        const proteinCal = target * proteinPercent;
        const fatCal = target * fatPercent;
        const carbsCal = target * carbPercent;
        
        return {
            protein: Math.round(proteinCal / 4),
            fat: Math.round(fatCal / 9),
            carbs: Math.round(carbsCal / 4),
        };
    };
    
    const dailyTargets = calculateDailyTargets(profile.dailyCalorieTarget, profile.goal); 

    const handleFileChange = (event) => {
        const file = event.target.files[0];
        if (file) {
            setUploadedFile(file);
            setUploadError('');
            setPrediction(null);
            setUploadMessage('');
        }
    };

    const handleSimulateUploadClick = () => {
        if (!mealType) {
            setUploadError("Please select a Meal Type before selecting an image.");
            return;
        }
        if (fileInputRef.current) {
            fileInputRef.current.click();
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setUploadError('');
        setUploadMessage('');
        setPrediction(null);
        
        if (!mealType) {
            setUploadError("Please select a Meal Type.");
            setLoading(false);
            return;
        }
        if (!uploadedFile) {
            setUploadError("Please select an image file first.");
            setLoading(false);
            return;
        }

        const payload = {
            mealType,
            imageUrl: uploadedFile.name, 
            filename: uploadedFile.name, 
        };

        try {
            const response = await api.post('/intake/upload-image', payload);
            
            setPrediction(response.data.prediction); 
            setUploadMessage("Meal logged successfully!");

            if (fetchNutrientWarnings) {
                await fetchNutrientWarnings(); 
            }

        } catch (err) {
            console.error('Meal upload failed:', err);
            setUploadError(err.response?.data?.message || 'Failed to log meal. Is the Python service running on Port 5001?');
        } finally {
            setLoading(false);
            setUploadedFile(null);
        }
    };

    const isReadyToEstimate = mealType && uploadedFile;
    
    const getMacroConicStyle = () => {
        const macro = prediction?.macroBreakdown;
        if (!macro) return { background: 'conic-gradient(#333 0deg)' };

        const total = macro.protein + macro.fat + macro.carbohydrates;
        if (total === 0) return { background: 'conic-gradient(#333 0deg)' };

        const p_end = (macro.protein / total) * 360;
        const f_end = p_end + (macro.fat / total) * 360;
        
        return {
            background: `conic-gradient(
                #ef4444 0deg ${p_end}deg,
                #f59e0b ${p_end}deg ${f_end}deg,
                #3b82f6 ${f_end}deg 360deg
            )`,
        };
    };

    return (
        <div className="space-y-6">
            {/* Header Info */}
            <div className="relative overflow-hidden rounded-2xl backdrop-blur-xl bg-slate-900/40 border border-slate-800/50 p-6 shadow-xl">
                <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-yellow-500 via-orange-500 to-red-500"></div>
                <p className="text-slate-300 leading-relaxed">
                    Upload a meal image to estimate calorie and macro intake. This requires <span className="font-semibold text-yellow-400">two steps</span>: 1) Select a meal type and Upload, then 2) Click Estimate & Log.
                </p>
            </div>

            {/* Upload Form Card */}
            <div className="relative overflow-hidden rounded-2xl backdrop-blur-xl bg-slate-900/40 border border-slate-800/50 p-6 shadow-xl">
                <form onSubmit={handleSubmit} className="space-y-6">
                    
                    {/* Meal Type Selection */}
                    <div>
                        <label htmlFor="mealType" className="block text-sm font-semibold text-slate-300 mb-2">
                            Meal Type
                        </label>
                        <select 
                            id="mealType"
                            value={mealType} 
                            onChange={(e) => {
                                setMealType(e.target.value);
                                setUploadedFile(null);
                            }}
                            className="w-full px-4 py-3 rounded-xl bg-slate-800/50 border border-slate-700/50 text-white focus:outline-none focus:ring-2 focus:ring-yellow-500/50 focus:border-yellow-500/50 transition-all"
                        >
                            <option value="">-- Select Meal Type --</option> 
                            <option value="Breakfast">🌅 Breakfast</option>
                            <option value="Lunch">☀️ Lunch</option>
                            <option value="Dinner">🌙 Dinner</option>
                            <option value="Snack">🍎 Snack</option>
                        </select>
                    </div>
                    
                    {/* Hidden File Input */}
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={handleFileChange} 
                        style={{ display: 'none' }} 
                        accept="image/*"
                    />

                    {/* Visual Upload Area */}
                    <div className="relative overflow-hidden p-8 border-2 border-dashed border-slate-700/50 rounded-2xl bg-slate-950/30 transition-all hover:border-yellow-500/50">
                        {uploadedFile ? (
                            <div className="text-center">
                                <div className="w-20 h-20 rounded-full bg-gradient-to-br from-emerald-500/20 to-teal-600/20 border-2 border-emerald-500/40 flex items-center justify-center mx-auto mb-4">
                                    <FaCheckCircle className="text-4xl text-emerald-400" />
                                </div>
                                <p className="text-emerald-400 font-bold mb-1">Image Selected</p>
                                <p className="text-sm text-slate-400 mb-3">{uploadedFile.name}</p>
                                <p className="text-xs text-slate-500 mb-4">Click 'Estimate & Log Meal' below to analyze</p>
                                <button 
                                    type="button" 
                                    onClick={() => setUploadedFile(null)} 
                                    className="inline-flex items-center gap-2 px-4 py-2 rounded-lg bg-red-500/20 border border-red-500/40 text-red-400 hover:bg-red-500/30 transition-all"
                                >
                                    <FaTimesCircle /> Remove File
                                </button>
                            </div>
                        ) : (
                            <div className="text-center">
                                <div className="w-20 h-20 rounded-full bg-slate-800/50 border-2 border-slate-700/50 flex items-center justify-center mx-auto mb-4">
                                    <FaCamera className="text-4xl text-slate-500" />
                                </div>
                                <p className="text-slate-400 mb-4">Select a file to begin estimation</p>
                                <button 
                                    type="button" 
                                    onClick={handleSimulateUploadClick}
                                    disabled={!mealType}
                                    className="group relative overflow-hidden px-6 py-3 rounded-xl bg-gradient-to-r from-yellow-500 to-orange-600 text-white font-bold transition-all duration-300 hover:scale-105 disabled:opacity-50 disabled:hover:scale-100 shadow-lg hover:shadow-yellow-500/50"
                                >
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent translate-x-[-200%] group-hover:translate-x-[200%] transition-transform duration-700"></div>
                                    <span className="relative z-10">
                                        {mealType ? 'Select Image from Files' : 'Select Meal Type First'}
                                    </span>
                                </button>
                            </div>
                        )}
                    </div>
                    
                    {/* Submit Button */}
                    <button 
                        type="submit" 
                        disabled={loading || !isReadyToEstimate} 
                        className="group relative overflow-hidden w-full px-6 py-4 rounded-xl bg-gradient-to-r from-orange-500 to-red-600 text-white font-bold transition-all duration-300 hover:scale-105 disabled:opacity-50 disabled:hover:scale-100 shadow-lg hover:shadow-orange-500/50 flex items-center justify-center gap-3"
                    >
                        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent translate-x-[-200%] group-hover:translate-x-[200%] transition-transform duration-700"></div>
                        
                        {loading ? (
                            <>
                                <FaSpinner className="relative z-10 animate-spin text-xl" />
                                <span className="relative z-10">Analyzing Meal...</span>
                            </>
                        ) : (
                            <>
                                <FaUpload className="relative z-10 text-xl" />
                                <span className="relative z-10">Estimate & Log Meal</span>
                            </>
                        )}
                    </button>
                    
                    {uploadError && (
                        <div className="p-4 rounded-xl bg-red-900/30 border border-red-500/40 text-red-400">
                            {uploadError}
                        </div>
                    )}
                </form>
            </div>
            
            {uploadMessage && (
                <div className="p-4 rounded-xl bg-emerald-900/30 border border-emerald-500/40 text-emerald-400 flex items-center gap-3">
                    <FaCheckCircle className="text-xl" />
                    <span className="font-semibold">{uploadMessage}</span>
                </div>
            )}

            {/* Results Display */}
            {prediction && (
                <div className="relative overflow-hidden rounded-2xl backdrop-blur-xl bg-slate-900/40 border border-slate-800/50 p-6 shadow-xl space-y-6">
                    <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-yellow-500 to-orange-500"></div>
                    
                    {/* Header */}
                    <div className="flex items-center gap-4 pb-4 border-b border-slate-800">
                        <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-yellow-500/20 to-orange-600/20 border border-yellow-500/40 flex items-center justify-center">
                            <span className="text-2xl">🍽️</span>
                        </div>
                        <div>
                            <h4 className="text-2xl font-bold bg-gradient-to-r from-yellow-400 to-orange-400 bg-clip-text text-transparent">
                                Estimation Result & Daily Impact
                            </h4>
                            <div className="h-1 w-32 bg-gradient-to-r from-yellow-500 to-orange-500 rounded-full mt-1"></div>
                        </div>
                    </div>
                    
                    {/* Summary */}
                    <div className="grid grid-cols-2 gap-4">
                        <div className="p-4 rounded-xl bg-slate-800/50 border border-slate-700/50">
                            <p className="text-xs text-slate-400 mb-1">Food Identified</p>
                            <p className="text-lg font-bold text-white">{prediction.foodName}</p>
                        </div>
                        <div className="p-4 rounded-xl bg-slate-800/50 border border-slate-700/50">
                            <p className="text-xs text-slate-400 mb-1">Estimated Calories</p>
                            <p className="text-lg font-bold text-emerald-400">{prediction.caloriesEstimated} kcal</p>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        
                        {/* Pie Chart Visualization */}
                        <div className="p-6 rounded-xl bg-slate-800/50 border border-slate-700/50">
                            <h5 className="font-bold text-slate-300 mb-4 flex items-center gap-2">
                                <FaChartPie className='text-red-400' /> Meal Macro Ratio
                            </h5>
                            <div className="flex justify-center items-center gap-4">
                                {/* Pie Chart */}
                                <div className="h-24 w-24 rounded-full border-4 border-slate-900" style={getMacroConicStyle()}></div>
                                
                                {/* Legend */}
                                <div className="text-xs space-y-2">
                                    <p className="flex items-center gap-2">
                                        <span className="h-3 w-3 bg-red-500 rounded-full"></span>
                                        <span className="text-slate-300">Protein</span>
                                    </p>
                                    <p className="flex items-center gap-2">
                                        <span className="h-3 w-3 bg-yellow-500 rounded-full"></span>
                                        <span className="text-slate-300">Fat</span>
                                    </p>
                                    <p className="flex items-center gap-2">
                                        <span className="h-3 w-3 bg-blue-500 rounded-full"></span>
                                        <span className="text-slate-300">Carbs</span>
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* Progress Bars */}
                        <div className="md:col-span-2 p-6 rounded-xl bg-slate-800/50 border border-slate-700/50 space-y-4">
                            <h5 className="font-bold text-slate-300 flex items-center gap-2 mb-4">
                                <FaChartBar className='text-blue-400' /> Daily Target Progress (Grams)
                            </h5>
                            
                            {['protein', 'fat', 'carbohydrates'].map(macroKey => {
                                const target = dailyTargets[macroKey];
                                const intake = prediction.macroBreakdown?.[macroKey] || 0;
                                
                                const percentage = target > 0 ? Math.round((intake / target) * 100) : 0;
                                const barWidth = Math.min(100, percentage);
                                
                                const colorClass = macroKey === 'protein' ? 'from-red-500 to-rose-600' : 
                                                   macroKey === 'fat' ? 'from-yellow-500 to-amber-600' : 
                                                   'from-blue-500 to-cyan-600';
                                
                                const targetDisplay = target > 0 ? `${target}g` : 'N/A';
                                const percentageDisplay = target > 0 ? `${percentage}%` : '---';

                                return (
                                    <div key={macroKey}>
                                        <div className="flex justify-between items-center mb-2">
                                            <span className="capitalize text-slate-300 font-semibold">
                                                {macroKey}: <span className="text-white">{intake}g</span> / {targetDisplay}
                                            </span>
                                            <span className="font-bold text-slate-400">{percentageDisplay}</span>
                                        </div>
                                        <div className="relative w-full bg-slate-950/50 rounded-full h-3 overflow-hidden">
                                            <div 
                                                className={`h-full rounded-full bg-gradient-to-r ${colorClass} transition-all duration-1000 shadow-lg`}
                                                style={{ width: `${barWidth}%` }}
                                            ></div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CalorieUpload;
